import{_ as h,o as n,c as a,a0 as i}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Thiết lập Kho","description":"","frontmatter":{"title":"Thiết lập Kho"},"headers":[],"relativePath":"stock-settings.md","filePath":"stock-settings.md"}'),o={name:"stock-settings.md"};function r(l,t,c,e,g,u){return n(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="thiet-lap-kho" tabindex="-1">Thiết lập Kho <a class="header-anchor" href="#thiet-lap-kho" aria-label="Permalink to &quot;Thiết lập Kho&quot;">​</a></h1><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Thiết lập Kho (Stock Settings) cho phép bạn cấu hình các hành vi mặc định cho mô-đun Kho trong ABNERP. Các thiết lập này ảnh hưởng trực tiếp đến cách hệ thống xử lý nhập xuất tồn, tính giá vốn và kiểm soát hàng tồn kho.</p><h2 id="cach-truy-cap" tabindex="-1">Cách truy cập <a class="header-anchor" href="#cach-truy-cap" aria-label="Permalink to &quot;Cách truy cập&quot;">​</a></h2><p>Vào <strong>Kho &gt; Thiết lập &gt; Thiết lập Kho</strong>, hoặc tìm kiếm &quot;Thiết lập Kho&quot; từ thanh tìm kiếm toàn cầu.</p><h2 id="cac-thiet-lap-chinh" tabindex="-1">Các thiết lập chính <a class="header-anchor" href="#cac-thiet-lap-chinh" aria-label="Permalink to &quot;Các thiết lập chính&quot;">​</a></h2><h3 id="phuong-phap-tinh-gia-xuat-kho" tabindex="-1">Phương pháp tính giá xuất kho <a class="header-anchor" href="#phuong-phap-tinh-gia-xuat-kho" aria-label="Permalink to &quot;Phương pháp tính giá xuất kho&quot;">​</a></h3><p>ABNERP hỗ trợ các phương pháp tính giá xuất kho sau:</p><table tabindex="0"><thead><tr><th>Phương pháp</th><th>Mô tả</th><th>Phù hợp</th></tr></thead><tbody><tr><td>FIFO (First In, First Out)</td><td>Hàng nhập trước xuất trước</td><td>Hàng hóa có hạn sử dụng, thời trang</td></tr><tr><td>Bình quân gia quyền (Moving Average)</td><td>Giá trị bình quân sau mỗi lần nhập</td><td>Hàng hóa thông thường</td></tr></tbody></table><p>Việc chọn phương pháp ảnh hưởng trực tiếp đến giá vốn hàng bán và giá trị tồn kho.</p><h3 id="ton-kho-am" tabindex="-1">Tồn kho âm <a class="header-anchor" href="#ton-kho-am" aria-label="Permalink to &quot;Tồn kho âm&quot;">​</a></h3><ul><li><strong>Cho phép tồn kho âm</strong>: Khi bật, hệ thống cho phép xuất hàng ngay cả khi tồn kho không đủ. Chỉ nên bật trong một số trường hợp đặc biệt.</li><li><strong>Cảnh báo tồn kho âm</strong>: Hiển thị cảnh báo khi cố gắng xuất vượt quá tồn kho hiện có.</li></ul><h3 id="cap-nhat-ton-kho" tabindex="-1">Cập nhật tồn kho <a class="header-anchor" href="#cap-nhat-ton-kho" aria-label="Permalink to &quot;Cập nhật tồn kho&quot;">​</a></h3><ul><li><strong>Cập nhật tồn kho tự động</strong>: Tự động cập nhật số lượng tồn kho khi lưu giao dịch.</li><li><strong>Tồn kho theo thời gian thực</strong>: Đảm bảo số liệu tồn kho luôn chính xác theo thời gian thực.</li><li><strong>Cập nhật hàng loạt</strong>: Cho phép cập nhật giá và tồn kho hàng loạt cho nhiều mặt hàng.</li></ul><h3 id="thiet-lap-kho-mac-đinh" tabindex="-1">Thiết lập kho mặc định <a class="header-anchor" href="#thiet-lap-kho-mac-đinh" aria-label="Permalink to &quot;Thiết lập kho mặc định&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thiết lập</th><th>Mô tả</th></tr></thead><tbody><tr><td>Kho nhập mặc định</td><td>Kho được chọn tự động khi nhập hàng</td></tr><tr><td>Kho xuất mặc định</td><td>Kho được chọn tự động khi xuất hàng</td></tr><tr><td>Kho trung chuyển</td><td>Kho dùng trong giao dịch chuyển kho</td></tr></tbody></table><h3 id="đon-vi-tinh" tabindex="-1">Đơn vị tính <a class="header-anchor" href="#đon-vi-tinh" aria-label="Permalink to &quot;Đơn vị tính&quot;">​</a></h3><ul><li><strong>Đơn vị tính mặc định</strong>: Đơn vị tính được chọn tự động khi tạo mặt hàng mới.</li><li><strong>Chuyển đổi đơn vị</strong>: Cho phép nhập/xuất hàng ở đơn vị tính khác với đơn vị cơ bản.</li></ul><h3 id="kiem-soat-chat-luong" tabindex="-1">Kiểm soát chất lượng <a class="header-anchor" href="#kiem-soat-chat-luong" aria-label="Permalink to &quot;Kiểm soát chất lượng&quot;">​</a></h3><ul><li><strong>Kiểm tra chất lượng khi nhập kho</strong>: Yêu cầu thực hiện kiểm tra chất lượng trước khi nhập.</li><li><strong>Kiểm tra chất lượng khi xuất kho</strong>: Yêu cầu kiểm tra chất lượng trước khi xuất.</li><li><strong>Mẫu kiểm tra mặc định</strong>: Mẫu kiểm tra chất lượng được áp dụng tự động.</li></ul><h3 id="lo-va-serial-number" tabindex="-1">Lô và Serial Number <a class="header-anchor" href="#lo-va-serial-number" aria-label="Permalink to &quot;Lô và Serial Number&quot;">​</a></h3><ul><li><strong>Tự động tạo số lô</strong>: Tự động sinh số lô dựa trên mẫu định trước.</li><li><strong>Bắt buộc Serial Number</strong>: Yêu cầu nhập serial number cho mặt hàng có quản lý serial.</li><li><strong>Kiểm tra trùng lặp Serial</strong>: Ngăn nhập serial number đã tồn tại.</li></ul><h3 id="san-xuat-va-lap-rap" tabindex="-1">Sản xuất và Lắp ráp <a class="header-anchor" href="#san-xuat-va-lap-rap" aria-label="Permalink to &quot;Sản xuất và Lắp ráp&quot;">​</a></h3><ul><li><strong>Tự động tạo phiếu xuất nguyên vật liệu</strong>: Khi tạo lệnh sản xuất, hệ thống tự động tạo phiếu xuất NVL.</li><li><strong>Tự động tạo phiếu nhập thành phẩm</strong>: Khi hoàn thành sản xuất, hệ thống tự động nhập kho thành phẩm.</li></ul><h3 id="bao-cao-va-hien-thi" tabindex="-1">Báo cáo và hiển thị <a class="header-anchor" href="#bao-cao-va-hien-thi" aria-label="Permalink to &quot;Báo cáo và hiển thị&quot;">​</a></h3><ul><li><strong>Định dạng báo cáo</strong>: Chọn định dạng hiển thị cho các báo cáo kho (số lượng, giá trị, cả hai).</li><li><strong>Số thập phân</strong>: Số chữ số thập phân hiển thị cho số lượng và đơn giá.</li></ul><h2 id="luu-y-quan-trong" tabindex="-1">Lưu ý quan trọng <a class="header-anchor" href="#luu-y-quan-trong" aria-label="Permalink to &quot;Lưu ý quan trọng&quot;">​</a></h2><ul><li>Phương pháp tính giá xuất kho KHÔNG thể thay đổi sau khi đã phát sinh giao dịch</li><li>Cho phép tồn kho âm tiềm ẩn rủi ro sai lệch số liệu — nên tắt trừ trường hợp thực sự cần</li><li>Nên kiểm tra kỹ các thiết lập trước khi đưa hệ thống vào sử dụng chính thức</li><li>Thay đổi kho mặc định chỉ ảnh hưởng đến giao dịch mới tạo sau khi thay đổi</li></ul>',28)])])}const d=h(o,[["render",r]]);export{p as __pageData,d as default};
